public with sharing class AccountDiscountService {
  public static Integer calculateDiscount(Account acct) {
    if (acct == null || acct.AnnualRevenue == null) {
      return 0;
    }
    if (acct.AnnualRevenue > 1000000) {
      return 20;
    }
    if (acct.AnnualRevenue > 250000) {
      return 10;
    }
    return 0;
  }
}

@IsTest
private class AccountDiscountServiceTest {
  @IsTest
  static void calculatesDiscounts() {
    Account enterpriseAcct = new Account(Name = 'Enterprise', AnnualRevenue = 1500000);
    System.assertEquals(20, AccountDiscountService.calculateDiscount(enterpriseAcct));
  }
}

trigger ContactTrigger on Contact (after insert, after update, after delete, after undelete) {
  ContactTriggerHandler.updateAccountCounts(Trigger.new, Trigger.oldMap);
}

public with sharing class ContactTriggerHandler {
  public static void updateAccountCounts(List<Contact> newList, Map<Id, Contact> oldMap) {
    Set<Id> accountIds = new Set<Id>();
    for (Contact c : newList == null ? new List<Contact>() : newList) {
      if (c.AccountId != null) accountIds.add(c.AccountId);
    }
    for (Contact c : oldMap == null ? new List<Contact>() : oldMap.values()) {
      if (c.AccountId != null) accountIds.add(c.AccountId);
    }
    if (accountIds.isEmpty()) return;
    Map<Id, Integer> counts = new Map<Id, Integer>();
    for (AggregateResult ar : [SELECT AccountId accountId, COUNT(Id) total FROM Contact WHERE AccountId IN :accountIds GROUP BY AccountId]) {
      counts.put((Id) ar.get('accountId'), (Integer) ar.get('total'));
    }
    List<Account> updates = new List<Account>();
    for (Id accountId : accountIds) {
      updates.add(new Account(Id = accountId, Number_of_Contacts__c = counts.get(accountId) == null ? 0 : counts.get(accountId)));
    }
    update updates;
  }
}

@IsTest
private class ContactTriggerHandlerTest {
  @IsTest
  static void updatesCount() {
    Account acct = new Account(Name = 'Acme');
    insert acct;
    insert new Contact(LastName = 'One', AccountId = acct.Id);
    Account refreshed = [SELECT Number_of_Contacts__c FROM Account WHERE Id = :acct.Id];
    System.assertEquals(1, refreshed.Number_of_Contacts__c);
  }
}

function filterAccounts(accounts, searchTerm) {
  const term = String(searchTerm || '').toLowerCase();
  if (!term) return [...accounts];
  return accounts.filter(account => String(account.Name || '').toLowerCase().includes(term));
}
window.filterAccounts = filterAccounts;

public with sharing class AccountEnrichmentClient {
  public static Map<String, Object> fetchDetails(String externalId) {
    HttpRequest req = new HttpRequest();
    req.setEndpoint('callout:Account_Service/accounts/' + EncodingUtil.urlEncode(externalId, 'UTF-8'));
    req.setMethod('GET');
    HttpResponse res = new Http().send(req);
    if (res.getStatusCode() < 200 || res.getStatusCode() >= 300) {
      throw new CalloutException('Account service failed: ' + res.getStatus());
    }
    return (Map<String, Object>) JSON.deserializeUntyped(res.getBody());
  }
}

@IsTest
private class AccountEnrichmentClientTest {
  private class SuccessMock implements HttpCalloutMock {
    public HTTPResponse respond(HTTPRequest req) {
      HttpResponse res = new HttpResponse();
      res.setStatusCode(200);
      res.setBody('{"tier":"Gold"}');
      return res;
    }
  }
  @IsTest static void parsesResponse() {
    Test.setMock(HttpCalloutMock.class, new SuccessMock());
    System.assertEquals('Gold', AccountEnrichmentClient.fetchDetails('A-1').get('tier'));
  }
}

public with sharing class AccountHealthBatch implements Database.Batchable<SObject> {
  public Database.QueryLocator start(Database.BatchableContext bc) {
    return Database.getQueryLocator([SELECT Id, Health_Status__c FROM Account WHERE IsDeleted = false]);
  }
  public void execute(Database.BatchableContext bc, List<Account> scope) {
    for (Account acct : scope) {
      acct.Health_Status__c = 'Review';
    }
    update scope;
  }
  public void finish(Database.BatchableContext bc) {
    // Send monitoring event or summary email if required.
  }
}

